import{_ as a,c as s,o as r,ak as o,al as t}from"./chunks/framework.B95DSy-a.js";const f=JSON.parse('{"title":"AireForms Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireforms-v11-2-0.md","filePath":"aireblock-releases/aireforms-v11-2-0.md","lastUpdated":1772706516000}'),i={name:"aireblock-releases/aireforms-v11-2-0.md"};function n(l,e,c,d,u,h){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="aireforms-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+t+'"> AireForms Release Notes</span> <a class="header-anchor" href="#aireforms-release-notes" aria-label="Permalink to “AireForms Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 11.2.0<br><strong>Release Date:</strong> 16 February 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Graceful Error Handling When Saving Building Blocks (AFORMS-4058)</li><li>reCAPTCHA Disabled by Default (AFORMS-4091)</li><li>Pass Custom Data into Form Instances (AFORMS-4095)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Improved Page Breaking for Large Tables in PDF Exports (AFORMS-4094)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="graceful-error-handling-when-saving-building-blocks-aforms-4058" tabindex="-1">Graceful Error Handling When Saving Building Blocks (AFORMS-4058) <a class="header-anchor" href="#graceful-error-handling-when-saving-building-blocks-aforms-4058" aria-label="Permalink to “Graceful Error Handling When Saving Building Blocks (AFORMS-4058)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Previously, if a server error occurred whilst saving a building block, users were redirected to an unexpected error page and lost all unsaved changes. The building block designer now stays open when a save error occurs, displaying a validation message so users can attempt further edits or undo recent changes before retrying.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If something goes wrong whilst saving your work in the building block designer, you will no longer be taken away from the page or lose your changes. Instead, a message will appear on screen letting you know there was a problem, so you can try undoing recent changes and attempt to save again.</p></div><h4 id="recaptcha-enabled-by-default-aforms-4095" tabindex="-1">reCAPTCHA Enabled by Default (AFORMS-4095) <a class="header-anchor" href="#recaptcha-enabled-by-default-aforms-4095" aria-label="Permalink to “reCAPTCHA Enabled by Default (AFORMS-4095)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>reCAPTCHA will be an opt out by default across all organisations. Organisations can opt out of reCAPTCHA via the <code>orgs.xml</code> configuration file.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>ReCAPTCHA Form submission can be toggled on or off for all users. If your organisation previously experienced issues with users being unable to complete or submit forms due to reCAPTCHA, this change resolves those problems.</p></div><h4 id="pass-custom-data-into-form-instances-aforms-4095" tabindex="-1">Pass Custom Data into Form Instances (AFORMS-4095) <a class="header-anchor" href="#pass-custom-data-into-form-instances-aforms-4095" aria-label="Permalink to “Pass Custom Data into Form Instances (AFORMS-4095)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Forms now support the ability to pass key-value pairs of data at the point of creating a form instance. This data is stored against the form instance and exposed within the form context, allowing configurators to surface contextual information within the form without requiring end users to enter it manually. See the updated <a href="https://docs.forms.aireinnovate.com/developers/api/instance-apis.html#create-form-instances-for-a-given-patient" target="_blank" rel="noreferrer">Developer documentation</a> for more details.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When a form is opened, it can now automatically include pre-filled contextual information that was passed in when the form was created. This means users may see relevant details already populated in their form, reducing the need for manual data entry.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="improved-page-breaking-for-large-tables-in-pdf-exports-aforms-4094" tabindex="-1">Improved Page Breaking for Large Tables in PDF Exports (AFORMS-4094) <a class="header-anchor" href="#improved-page-breaking-for-large-tables-in-pdf-exports-aforms-4094" aria-label="Permalink to “Improved Page Breaking for Large Tables in PDF Exports (AFORMS-4094)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where large HTML tables added to PDFs via server-side calculations were not page-breaking correctly, resulting in table content being cut off or overflowing across pages.</p></div>',24)])])}const p=a(i,[["render",n]]);export{f as __pageData,p as default};
